var minimumMoves = function(nums, k, maxChanges) {
    const n = nums.length;
    const ones = [];
    for (let i = 0; i < n; i++) if (nums[i] === 1) ones.push(i);

    let ans = Infinity;

    for (let alice = 0; alice < n; alice++) {
        let collected = 0, cost = 0;
        const used = new Set();

        // Tier 0: alice's own position (0 moves)
        if (nums[alice] === 1) { used.add(alice); collected++; }
        if (collected >= k) { ans = Math.min(ans, cost); continue; }

        // Tier 1: adjacent ones (1 move each)
        if (alice > 0 && nums[alice-1] === 1 && !used.has(alice-1)) {
            used.add(alice-1); collected++; cost++;
        }
        if (collected < k && alice < n-1 && nums[alice+1] === 1 && !used.has(alice+1)) {
            used.add(alice+1); collected++; cost++;
        }
        if (collected >= k) { ans = Math.min(ans, cost); continue; }

        // Tier 2: changes (2 moves each)
        const useChg = Math.min(maxChanges, k - collected);
        cost += useChg * 2; collected += useChg;
        if (collected >= k) { ans = Math.min(ans, cost); continue; }

        // Tier 3: slide from remaining ones
        const pool = ones
            .filter(i => !used.has(i))
            .sort((a, b) => Math.abs(a-alice) - Math.abs(b-alice));
        const need = k - collected;
        if (pool.length < need) continue;
        let slideCost = 0;
        for (let i = 0; i < need; i++) slideCost += Math.abs(pool[i] - alice);
        ans = Math.min(ans, cost + slideCost);
    }
    return ans;
};
